-- SENT (Sentenças) — 29 colunas, ordem do CSV (codigos_classes ANTES de codigo_ultima_classe)
\COPY sent(tribunal,grau,nome_orgao,uf,municipio,ano,mes,processo,codigos_classes,codigo_ultima_classe,nome_ultima_classe,codigos_assuntos,data_referencia,data_julgamento_sit_mov,data_decisao_sit_mov,formato,procedimento,recurso,codigo_orgao,id_municipio,polo_ativo,polo_ativo_cnpj,polo_ativo_natureza,polo_ativo_cnae,polo_passivo,polo_passivo_cnpj,polo_passivo_natureza,polo_passivo_cnae,poder_publico) FROM '/data/TRE-GO_Sent.csv' WITH (FORMAT csv, DELIMITER ';', HEADER true, ENCODING 'UTF8', NULL '');

-- TBAIX (Casos Baixados) — 29 colunas
