atureza_passivo,cnae_passivo,segmento_passivo,poder_publico,ano_eleicao,id_orgao_julgador_colegiado,assistencia_judiciaria,flg_pedido_prioridade,flg_nucleo_4,flg_juizo_100_digital,custas_iniciais,custas_recursais,custas_finais,millisinsercao,created_at,updated_at) FROM '/data/1)Extrai_Datamart_TRE-GO.csv' WITH (FORMAT csv, DELIMITER ';', HEADER true, ENCODING 'UTF8', NULL '');

-- Estatísticas pós-import
ANALYZE cn;
ANALYZE sent;
ANALYZE tbaix;
ANALYZE cpl;
ANALYZE datamart;

EOSQL

echo "=== Seed concluído com sucesso ==="
echo "Contagem de registros:"
psql -U datajud -d datajud -c "SELECT 'cn' as tabela, count(*) FROM cn UNION ALL SELECT 'sent', count(*) FROM sent UNION ALL SELECT 'tbaix', count(*) FROM tbaix UNION ALL SELECT 'cpl', count(*) FROM cpl UNION ALL SELECT 'datamart', count(*) FROM datamart;"
